async fn parse_file_for_staged(
    seq: usize,
    path: std::path::PathBuf,
    path_str: String,
    project_id: String,
    content: String,
    file_hash: String,
    read_elapsed_ms: u128,
    byte_permits: Option<tokio::sync::OwnedSemaphorePermit>,
    parse_worker_permits: Arc<tokio::sync::Semaphore>,
) -> ParsedFile {
    let _parse_worker_permit = match parse_worker_permits.acquire_owned().await {
        Ok(permit) => permit,
        Err(e) => {
            return ParsedFile {
                seq,
                path,
                path_str,
                file_hash: None,
                chunks: vec![],
                symbols: vec![],
                references: vec![],
                read_elapsed_ms,
                parse_elapsed_ms: 0,
                error: Some(format!("parse worker permit unavailable: {e}")),
                skipped: false,
            };
        }
    };
    let parse_path = path.clone();
    let join = tokio::task::spawn_blocking(move || {
        let _byte_permits = byte_permits;
        let parse_started = Instant::now();
        let chunks = chunk_file(&parse_path, &content, &project_id);
        let (symbols, references) = CodeParser::parse_file(&parse_path, &content, &project_id);
        (chunks, symbols, references, parse_started.elapsed().as_millis())
    });

    match tokio::time::timeout(Duration::from_secs(PARSE_TIMEOUT_SECS), join).await {
        Ok(Ok((chunks, symbols, references, parse_elapsed_ms))) => ParsedFile {
            seq,
            path,
            path_str,
            file_hash: Some(file_hash),
            chunks,
            symbols,
            references,
            read_elapsed_ms,
            parse_elapsed_ms,
            error: None,
            skipped: false,
        },
        Ok(Err(e)) => ParsedFile {
            seq,
            path,
            path_str,
            file_hash: None,
            chunks: vec![],
            symbols: vec![],
            references: vec![],
            read_elapsed_ms,
            parse_elapsed_ms: 0,
            error: Some(format!("parse/chunk panicked: {e}")),
            skipped: false,
        },
        Err(_) => ParsedFile {
            seq,
            path,
            path_str,
            file_hash: None,
            chunks: vec![],
            symbols: vec![],
            references: vec![],
            read_elapsed_ms,
            parse_elapsed_ms: 0,
            error: Some(format!("parse_timeout_{}s", PARSE_TIMEOUT_SECS)),
            skipped: false,
        },
    }
}

