fn symbol_exactness_score(
    sym: &crate::types::CodeSymbol,
    query_lower: &str,
    terms: &[String],
) -> f32 {
    let name_lower = sym.name.to_lowercase();
    let sig_lower = sym.signature.clone().unwrap_or_default().to_lowercase();
    let name_tokens = split_identifier_tokens(&sym.name);
    let mut matched_terms = 0usize;
    let mut raw = 0.0f32;

    if name_lower == query_lower {
        raw += 2.2;
    } else if query_lower.len() >= 4 && name_lower.contains(query_lower) {
        raw += 1.6;
    }
    if !sig_lower.is_empty() && query_lower.len() >= 4 && sig_lower.contains(query_lower) {
        raw += 0.8;
    }

    for t in terms {
        if t.len() < 2 {
            continue;
        }
        if name_tokens.iter().any(|nt| nt == t) {
            matched_terms += 1;
            raw += 0.55;
        } else if name_lower.contains(t) || sig_lower.contains(t) {
            matched_terms += 1;
            raw += 0.35;
        }
    }
    if !terms.is_empty() {
        raw += 0.8 * (matched_terms as f32 / terms.len() as f32);
    }

    raw.clamp(0.0, 4.0) / 4.0
}

async fn flush_staged_symbols(
    state: &Arc<AppState>,
    project_id: &str,
    status: &IndexStatus,
    total_relation_stats: &RelationStats,
    metrics: &mut IndexMetrics,
    batch: Vec<CodeSymbol>,
) -> Result<()> {
    if batch.is_empty() {
        return Ok(());
    }
    let batch_len = batch.len() as u64;
    let _permit = state.db_semaphore.acquire().await;
    let symbol_write_started = Instant::now();
    let ids = state.storage.create_code_symbols_batch(batch.clone()).await?;
    let symbol_write_elapsed = symbol_write_started.elapsed().as_millis();
    metrics.symbol_db_write_elapsed_ms += symbol_write_elapsed;
    metrics.symbols_written += batch_len;
    emit_index_timing(
        project_id,
        "symbol_db_write",
        symbol_write_elapsed,
        status.indexed_files as u64,
        status.total_chunks as u64,
        batch_len,
        (total_relation_stats.created + total_relation_stats.failed) as u64,
        status.failed_files.len() as u64,
    );

    for (id, sym) in ids.iter().zip(batch.iter()) {
        let embed_text = sym
            .signature
            .clone()
            .unwrap_or_else(|| format!("{} {}", sym.symbol_type, sym.name));
        let enqueue_started = Instant::now();
        if let Err(e) = state
            .embedding_queue
            .send(EmbeddingRequest {
                text: embed_text,
                responder: None,
                target: Some(EmbeddingTarget::Symbol(id.clone())),
                retry_count: 0,
            })
            .await
        {
            tracing::warn!(symbol_id = %id, error = %e, "Failed to enqueue symbol embedding");
        }
        metrics.embedding_enqueue_elapsed_ms += enqueue_started.elapsed().as_millis();
        metrics.embeddings_enqueued += 1;
    }

    Ok(())
}

