pub(crate) async fn index_project_after_admission(
    state: Arc<AppState>,
    project_path: &Path,
) -> Result<IndexStatus> {
    let project_id = derive_project_id(project_path)
        .map_err(|error| crate::AppError::InvalidPath(error.to_string()))?;

    let state_clone = state.clone();
    let project_path_clone = project_path.to_path_buf();
    let project_id_clone = project_id.clone();

    // Spawn as a task so we can catch panics natively
    let handle = tokio::spawn(async move {
        do_index_project(state_clone, &project_path_clone, &project_id_clone).await
    });

    tracing::info!(
        project_id = %project_id,
        root_path = %project_path.display(),
        "Awaiting one-shot code index task"
    );

    let result = match handle.await {
        Ok(res) => res,
        Err(join_err) => {
            let msg = if join_err.is_panic() {
                "Indexing panicked (crashed)".to_string()
            } else if join_err.is_cancelled() {
                "Indexing was cancelled".to_string()
            } else {
                "Indexing failed to complete".to_string()
            };
            Err(crate::AppError::Internal(msg.into()))
        }
    };

    match result {
        Ok(status) => Ok(status),
        Err(e) => {
            tracing::error!(project_id = %project_id, error = %e, "Indexing failed");
            if is_non_destructive_index_error(&e) {
                return Err(e);
            }
            let mut status = IndexStatus::new(project_id.clone());
            if let Ok(Some(existing)) = state.storage.get_index_status(&project_id).await {
                status = existing;
            }

            // Extract last known file if possible
            if let Some(monitor) = state.progress.get(&project_id).await {
                if let Ok(cf) = monitor.current_file.read() {
                    if !cf.is_empty() {
                        status.failed_files.push(cf.clone());
                        status.error_message = Some(format!("{}: Failed at file {}", e, cf));
                    } else {
                        status.error_message = Some(e.to_string());
                    }
                } else {
                    status.error_message = Some(e.to_string());
                }
            } else {
                status.error_message = Some(e.to_string());
            }

            status.status = IndexState::Failed;
            status.completed_at = Some(crate::types::Datetime::default());
            let _ = state.storage.update_index_status(status.clone()).await;
            Err(e)
        }
    }
}

pub(crate) async fn search_code_with_context(
    state: &Arc<AppState>,
    params: SearchCodeParams,
    context: Option<CodeToolContext>,
) -> anyhow::Result<CallToolResult> {
    crate::ensure_embedding_ready!(state);

    let SearchCodeParams {
        query,
        project_id,
        limit,
    } = params;
    let project_resolution =
        resolve_project_for_code_tool(state, normalize_project_id(project_id), context.as_ref())
            .await;
    let project_id = project_resolution.project_id().map(str::to_string);

    let mut is_partial = false;
    let mut indexing_message = None;

    let mut project_status = None;
    if let Some(ref project_id) = project_id {
        if let Ok(Some(status)) = state.storage.get_index_status(project_id).await {
            if status.status == crate::types::IndexState::Indexing
                || status.status == crate::types::IndexState::EmbeddingPending
            {
                is_partial = true;
                indexing_message = Some(format!(
                    "Indexing in progress ({}/{} files). Results may be incomplete.",
                    status.indexed_files, status.total_files
                ));
            }
            project_status = Some(status);
        }
    }

    let limit = normalize_limit(limit);

    if project_resolution.is_stale_binding() {
        let mut response = json!({
            "results": [],
            "count": 0,
            "summary": summary_collection_response(
                "collection",
                0,
                Some(0),
                true,
                Some("Session-bound project is stale; refusing cross-project fallback.".to_string()),
            ),
            "query": query,
            "contract": code_search_contract_json(project_id.as_deref(), project_status.as_ref()),
            "vector_hits": 0,
            "bm25_hits": 0,
            "is_partial": true,
            "message": "Session-bound project is stale; refusing cross-project fallback."
        });
        apply_project_resolution(&mut response, &project_resolution);
        return Ok(success_json(response));
    }

    let query_embedding = state.embedding.embed(&query).await?;

    // Run vector search and BM25 in parallel for robust results.
    // Previously BM25 was only a fallback — degenerate vectors masked BM25 entirely.
    let project_id = project_id.as_deref();
    let (vector_results, bm25_results) = tokio::join!(
        async {
            match state
                .storage
                .vector_search_code(&query_embedding, project_id, limit)
                .await
            {
                Ok(results) => {
                    tracing::debug!(hits = results.len(), "search_code: vector search completed");
                    results
                }
                Err(e) => {
                    tracing::warn!(error = %e, "search_code: vector search failed, falling back to empty");
                    Vec::new()
                }
            }
        },
        async {
            state
                .code_search
