        }
        "get_related" => {
            let entity_id = params.0.entity_id.ok_or_else(|| ErrorData {
                code: ErrorCode(-32602),
                message: "entity_id required for get_related".into(),
                data: None,
            })?;
            let related_params = GetRelatedParams {
